    def _handle_tool_calls(self, message) -> str:
        """Handle OpenAI function/tool calls"""
        
        # Add assistant message with tool calls to history
        self.conversation_history.append({
            "role": "assistant",
            "content": message.content,
            "tool_calls": [
                {
                    "id": tc.id,
                    "type": tc.type,
                    "function": {
                        "name": tc.function.name,
                        "arguments": tc.function.arguments
                    }
                } for tc in message.tool_calls
            ]
        })
        
        # Process each tool call
        for tool_call in message.tool_calls:
            function_name = tool_call.function.name
            
            try:
                function_args = json.loads(tool_call.function.arguments)
            except json.JSONDecodeError as e:
                logger.error(f"Error parsing function arguments: {e}")
                result = {"error": f"Invalid function arguments: {str(e)}"}
                self.conversation_history.append({
                    "role": "tool",
                    "tool_call_id": tool_call.id,
                    "content": json.dumps(result)
                })
                continue
            
            # Execute function
            try:
                if function_name == "search_artists":
                    result = self.db_validator.search_artists(function_args.get("search_term", ""))
                
                elif function_name == "search_institutions":
                    result = self.db_validator.search_institutions(
                        function_args.get("search_term", ""),
                        function_args.get("state")
                    )
                
                elif function_name == "get_event_modules":
                    result = self.db_validator.get_event_modules()
                
                elif function_name == "create_event":
                    event_data = function_args.get("event_data", {})
                    
                    # LOG WHAT WE RECEIVED
                    logger.info(f"Received event_data: {json.dumps(event_data, indent=2, default=str)}")
                    
                    # Validate required fields
                    required_fields = ['start_date', 'artist_name', 'institution_name', 'city', 'state']
                    missing_fields = [field for field in required_fields if not event_data.get(field)]
                    
                    if missing_fields:
                        error_msg = f"Missing required fields: {', '.join(missing_fields)}"
                        logger.error(error_msg)
                        logger.error(f"Current event_data keys: {list(event_data.keys())}")
                        result = {
                            "success": False,
                            "error": error_msg,
                            "hint": "Please make sure you have collected all information: date, artist, institution, city, state, and attendees before creating the event."
                        }

                    else:
                        result = self._create_event_and_apr(event_data)
                
                
                
                elif function_name == "add_new_artist":
                    artist_data = function_args.get("artist_data", {})
                    result = self.event_service.add_new_artist(artist_data)

                elif function_name == "add_new_institution":
                    institution_data = function_args.get("institution_data", {})
                    result = self.event_service.add_new_institution(institution_data)
                
                else:
                    result = {"error": f"Unknown function: {function_name}"}
                
                logger.error(f"Result of function output {function_name}: {result}")                    
                    
            except Exception as e:
                logger.error(f"Error executing function {function_name}: {e}")
                result = {"error": f"Function execution error: {str(e)}"}
            
            # Add function result to history
            self.conversation_history.append({
                "role": "tool",
                "tool_call_id": tool_call.id,
                "content": json.dumps(result)
            })
        
        # Get next response from OpenAI
        try:
            follow_up = self.client.chat.completions.create(
                model=self.model,
                messages=[
                    {"role": "system", "content": self.system_prompt},
                    *self.conversation_history
                ]
            )
            
            follow_up_message = follow_up.choices[0].message.content
            self.conversation_history.append({
                "role": "assistant",
                "content": follow_up_message
            })
            
            return follow_up_message
            
        except Exception as e:
            logger.error(f"Error getting follow-up response: {e}")
            return "I apologize, but I encountered an error processing your request. Let's continue - what would you like to do?"

